import React, { useState, useCallback } from 'react';
import { Button, Select, MoneyInput, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { ktService } from '../../../services/kt/ktService';
import type { OpeningBalanceDto } from '../../../services/kt/models';
import { yearOptions } from '../../../constants/voucher';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';
import erp from '../../../styles/erpPage.module.css';

const TEST_ID = 'erp-so-du-dau-ky';

const SoDuDauKyPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const [year, setYear] = useState(String(new Date().getFullYear()));
  const [items, setItems] = useState<OpeningBalanceDto[]>([]);
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);

  const load = useCallback(() => {
    setLoading(true);
    ktService.getOpeningBalances(Number(year))
      .then(setItems)
      .catch(err => dispatch(addToast({ message: getApiErrorMessage(err, 'Lỗi tải số dư'), type: 'error' })))
      .finally(() => setLoading(false));
  }, [year, dispatch]);

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => { if (!cancelled) load(); }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [load]);

  const updateItem = (idx: number, field: 'debitBalance' | 'creditBalance', val: number) => {
    setItems(prev => prev.map((it, i) => i === idx ? { ...it, [field]: val } : it));
  };

  const handleSave = async () => {
    setSaving(true);
    try {
      await ktService.saveOpeningBalances({ year: Number(year), items });
      dispatch(addToast({ message: 'Lưu số dư đầu kỳ thành công', type: 'success' }));
      load();
    } catch (e: unknown) {
      dispatch(addToast({ message: getApiErrorMessage(e, 'Lỗi lưu'), type: 'error' }));
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className={erp.page} data-testid={TEST_ID}>
      <div className={erp.pageHeader}>
        <div className={erp.titleBlock}><h1 className={erp.title}><i className="fas fa-balance-scale" /> Số dư đầu kỳ</h1></div>
      </div>
      <div className={erp.filtersBar} data-testid={`${TEST_ID}-filters`}>
        <Select
          value={year}
          onChange={e => setYear(e.target.value)}
          options={yearOptions()}
          data-testid={`${TEST_ID}-year`}
        />
        <Button variant="primary" onClick={handleSave} loading={saving} data-testid={`${TEST_ID}-save`}>Lưu</Button>
        <ListSearchRefreshButtons testIdPrefix={TEST_ID} onSearch={load} onRefresh={load} showSearch={false} />
      </div>
      <div className={erp.tableCard} data-testid={`${TEST_ID}-table`}>
        {loading ? <div className={erp.loading}>Đang tải...</div> : items.length === 0 ? (
          <div className={erp.empty} data-testid={`${TEST_ID}-empty`}>Chưa có tài khoản hoặc số dư năm {year}</div>
        ) : (
          <div className={erp.tableWrapper}>
            <table className={erp.table}>
              <thead><tr><th>TK</th><th>Tên TK</th><th>Đối tượng</th><th className={erp.colRight}>Dư Nợ</th><th className={erp.colRight}>Dư Có</th></tr></thead>
              <tbody>{items.map((it, idx) => (
                <tr key={`${it.accountCode}-${it.customerId ?? idx}`} data-testid={`${TEST_ID}-row-${idx + 1}`}>
                  <td><code>{it.accountCode}</code></td>
                  <td>{it.accountName}</td>
                  <td>{it.customerName ?? '—'}</td>
                  <td>
                    <MoneyInput
                      value={it.debitBalance}
                      onChange={val => updateItem(idx, 'debitBalance', val)}
                      data-testid={`${TEST_ID}-row-${idx + 1}-debit`}
                    />
                  </td>
                  <td>
                    <MoneyInput
                      value={it.creditBalance}
                      onChange={val => updateItem(idx, 'creditBalance', val)}
                      data-testid={`${TEST_ID}-row-${idx + 1}-credit`}
                    />
                  </td>
                </tr>
              ))}</tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

export default SoDuDauKyPage;
